import{_ as o,c as t,o as i,ag as n}from"./chunks/framework.Bw-5EFTY.js";const u=JSON.parse('{"title":"DAG Designer Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-designer/docs/SPEC.md","filePath":"packages/dag-designer/docs/SPEC.md"}'),d={name:"packages/dag-designer/docs/SPEC.md"};function a(c,e,r,s,l,g){return i(),t("div",null,e[0]||(e[0]=[n('<h1 id="dag-designer-specification" tabindex="-1">DAG Designer Specification <a class="header-anchor" href="#dag-designer-specification" aria-label="Permalink to &quot;DAG Designer Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Composable React DAG designer UI package. Provides components, hooks, and an API client for authoring DAG definitions, managing node catalogs, and executing runs with real-time progress streaming. Run execution is server-authoritative via API; the designer does not perform local orchestration.</p><p>Run client contract: <code>createRun -&gt; startRun -&gt; getRunResult</code>.</p><ul><li><code>createRun</code> returns <code>{ preparationId }</code> (orchestrator-internal pre-start key).</li><li><code>startRun</code> accepts <code>preparationId</code>, returns <code>{ dagRunId }</code> where <code>dagRunId</code> = <code>promptId</code> from runtime.</li><li><code>subscribeRunProgress</code> uses <code>preparationId</code> (WS connects before start).</li><li><code>getRunResult</code> uses <code>dagRunId</code>.</li><li><code>IRunResult</code> has <code>status</code> (<code>&#39;success&#39; | &#39;failed&#39;</code>), <code>traces</code>, <code>nodeErrors: IRunNodeError[]</code>, and <code>totalCredits</code>.</li></ul><p><code>text-template</code> node template syntax:</p><ul><li><code>%s</code>: replace with input text</li><li><code>%%s</code>: render literal <code>%s</code></li><li>default template is <code>%s</code> (pass-through behavior)</li></ul><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Depends on <code>dag-core</code> for domain types (<code>IDagDefinition</code>, <code>IDagNode</code>, <code>INodeManifest</code>, <code>TPortPayload</code>, <code>TRunProgressEvent</code>, etc.).</li><li>Does NOT import <code>dag-runtime</code>, <code>dag-worker</code>, or <code>dag-scheduler</code> implementations directly.</li><li>Does not own backend storage or execution infrastructure.</li><li>Does not own API contract definitions for the server side -- those belong to <code>dag-api</code>.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><ul><li><strong>Contracts</strong> (<code>contracts/designer-api.ts</code>): Defines the <code>IDesignerApiClient</code> interface and all request/response types for the designer-to-server communication.</li><li><strong>API Client</strong> (<code>client/designer-api-client.ts</code>): <code>DesignerApiClient</code> implements <code>IDesignerApiClient</code> using <code>fetch</code> for REST calls and <code>WebSocket</code> for run progress streaming with exponential backoff reconnection.</li><li><strong>React Hooks</strong>: <ul><li><code>useDagDesignerState()</code> -- accesses designer state (definition, manifests, selection, run result, run progress, errors).</li><li><code>useDagDesignerActions()</code> -- accesses designer mutation actions (updateDefinition, addNode, updateNode, updateEdge, setSelection, etc.).</li><li><code>useDagDesignApi(options)</code> -- provides a typed API facade wrapping <code>IDesignerApiClient</code> for React components.</li></ul></li><li><strong>React Components</strong> (<code>components/</code>): <ul><li><code>DagDesignerCanvas</code> -- main canvas with context provider</li><li><code>DagNodeView</code> -- node rendering</li><li><code>DagBindingEdge</code> -- edge rendering with binding visualization</li><li><code>NodeExplorerPanel</code> -- node catalog browser</li><li><code>NodeConfigPanel</code> -- node configuration editor</li><li><code>EdgeInspectorPanel</code> -- edge/binding inspector</li><li><code>NodeIoViewer</code> -- input/output data viewer</li><li><code>NodeIoTracePanel</code> -- execution trace viewer</li></ul></li><li><strong>Lifecycle</strong> (<code>lifecycle/run-engine.ts</code>): Re-exports <code>IRunNodeTrace</code> and <code>IRunResult</code> types.</li><li><strong>Utilities</strong>: <code>port-editor-utils.ts</code> (port editing helpers).</li><li><strong>Config Form</strong>: Node configuration uses ComfyUI <code>TInputTypeSpec</code> (from <code>/object_info</code>) instead of Zod schemas for field rendering.</li><li><strong>Node Catalog</strong>: <code>NodeExplorerPanel</code> uses <code>INodeObjectInfo</code>/<code>TObjectInfo</code> from the <code>/object_info</code> endpoint for node discovery and categorization.</li></ul><p><strong>INodeManifest vs TObjectInfo coexistence:</strong></p><ul><li><code>TObjectInfo</code>/<code>INodeObjectInfo</code> is the preferred path for node discovery (sourced from the <code>/object_info</code> API).</li><li><code>INodeManifest</code> is retained for backward compatibility in component props where existing consumers pass manifests directly.</li><li>Config form rendering uses ComfyUI <code>TInputTypeSpec</code> (from <code>/object_info</code>), not Zod schemas.</li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for:</p><ul><li><code>IDesignerApiClient</code> -- client interface for all designer-to-server API operations</li><li><code>IDesignerApiClientConfig</code> -- client configuration (baseUrl)</li><li><code>ICreateDefinitionInput</code>, <code>IUpdateDraftInput</code>, <code>IValidateDefinitionInput</code>, <code>IPublishDefinitionInput</code>, <code>IGetDefinitionInput</code>, <code>IListDefinitionsInput</code> -- client-side input types</li><li><code>IDesignerCreateRunInput</code>, <code>IDesignerStartRunInput</code>, <code>IGetRunResultInput</code> -- run operation inputs (designer-prefixed to avoid collision with dag-runtime)</li><li><code>ISubscribeRunProgressInput</code> -- run progress subscription input</li><li><code>IDagDesignerState</code> -- React designer state interface</li><li><code>IDagDesignerActions</code> -- React designer action interface</li><li><code>IUseDagDesignApi</code> -- hook return type interface</li><li><code>IUseDagDesignApiOptions</code> -- hook options interface</li><li><code>IRunProgressState</code> -- run progress tracking state</li></ul><p>Imported from other packages (not owned here):</p><ul><li><code>IProblemDetails</code>, <code>IDefinitionListItem</code> -- imported from <code>@robota-sdk/dag-api</code></li><li><code>IRunNodeTrace</code>, <code>IRunResult</code>, <code>IRunNodeError</code> -- imported from <code>@robota-sdk/dag-core</code></li></ul><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><ul><li><code>DesignerApiClient</code> -- HTTP/WebSocket client implementing <code>IDesignerApiClient</code></li><li><code>useDagDesignerState()</code> -- React hook for read-only designer state</li><li><code>useDagDesignerActions()</code> -- React hook for designer mutations</li><li><code>useDagDesignApi(options)</code> -- React hook wrapping API client</li><li><code>DagDesignerCanvas</code> -- main canvas React component</li><li><code>DagNodeView</code>, <code>DagBindingEdge</code> -- graph element components</li><li><code>NodeExplorerPanel</code>, <code>NodeConfigPanel</code>, <code>EdgeInspectorPanel</code> -- panel components</li><li><code>NodeIoViewer</code>, <code>NodeIoTracePanel</code> -- data/trace viewer components</li><li><code>listObjectInfo()</code> -- primary method on <code>IDesignerApiClient</code> for node catalog discovery (fetches <code>/object_info</code> from runtime)</li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><code>IDesignerApiClient</code> -- implement to provide a custom API client (e.g., mock client for testing, alternative transport).</li><li><code>useDagDesignApi({ client })</code> -- accepts a custom client instance, enabling dependency injection in React.</li><li>Canvas component accepts <code>onRunResult</code> callback for custom run result handling.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>Client-side errors use <code>IProblemDetails</code> (mirroring the server shape):</p><ul><li><code>DESIGNER_API_CONTRACT_VIOLATION</code> -- response payload does not match the expected designer API contract (type: <code>urn:robota:problems:dag:contract</code>)</li><li>Server-originated <code>IProblemDetails</code> errors are passed through from the API response.</li><li>WebSocket errors surface via <code>onError</code> callback: <code>&quot;WebSocket is not available in this environment.&quot;</code>, <code>&quot;Run progress stream disconnected.&quot;</code>, <code>&quot;Failed to parse run progress event payload.&quot;</code>.</li></ul><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>IDesignerApiClient</code></td><td><code>DesignerApiClient</code></td><td>production</td><td><code>src/client/designer-api-client.ts</code></td></tr></tbody></table><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. Classes are standalone.</p><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Consumer</th><th>Location</th></tr></thead><tbody><tr><td>Domain types from dag-core (<code>IDagDefinition</code>, <code>INodeManifest</code>, <code>TRunProgressEvent</code>)</td><td><code>DesignerApiClient</code>, hooks, components</td><td>Throughout <code>src/</code></td></tr></tbody></table><h2 id="list-port-handle-behavior" tabindex="-1">List Port Handle Behavior <a class="header-anchor" href="#list-port-handle-behavior" aria-label="Permalink to &quot;List Port Handle Behavior&quot;">​</a></h2><p>Ports with <code>isList: true</code> support multiple connections via dynamically generated handle slots.</p><h3 id="handle-rendering-dagnodeview" tabindex="-1">Handle Rendering (<code>DagNodeView</code>) <a class="header-anchor" href="#handle-rendering-dagnodeview" aria-label="Permalink to &quot;Handle Rendering (`DagNodeView`)&quot;">​</a></h3><ul><li><strong>Connected handles</strong>: One handle per existing binding to this list port across all incoming edges. Display: full opacity, label shows <code>#N</code> (1-based).</li><li><strong>Placeholder handle</strong>: Exactly one extra handle rendered beyond the connected count. Display: <code>opacity-50</code>, represents the next available slot for a new connection.</li><li><strong>No connections</strong>: One placeholder handle at index 0.</li><li><strong>Formula</strong>: <code>handleCount = connectedBindingCount + 1</code>. Handle IDs follow <code>portKey[index]</code> format (e.g., <code>images[0]</code>, <code>images[1]</code>).</li></ul><h3 id="connection-onconnect-in-dagdesignercanvas" tabindex="-1">Connection (<code>onConnect</code> in <code>DagDesignerCanvas</code>) <a class="header-anchor" href="#connection-onconnect-in-dagdesignercanvas" aria-label="Permalink to &quot;Connection (`onConnect` in `DagDesignerCanvas`)&quot;">​</a></h3><ul><li>Connecting to a placeholder handle creates a new binding with the placeholder&#39;s handle ID as <code>inputKey</code>.</li><li>Connecting to an already-bound handle is rejected with <code>&quot;Connection rejected: input handle is already bound.&quot;</code>.</li><li>After connection, <code>compactListBindings()</code> re-indexes all list bindings to ensure sequential indices starting from 0.</li><li>A new connection may create a new edge (if no edge exists between source and target) or append a binding to an existing edge.</li></ul><h3 id="compaction-compactlistbindings-in-canvas-utils" tabindex="-1">Compaction (<code>compactListBindings</code> in <code>canvas-utils</code>) <a class="header-anchor" href="#compaction-compactlistbindings-in-canvas-utils" aria-label="Permalink to &quot;Compaction (`compactListBindings` in `canvas-utils`)&quot;">​</a></h3><ul><li>Re-indexes list binding <code>inputKey</code> values to be sequential starting from 0 per (targetNodeId, listPortKey) pair.</li><li>Indices are tracked <strong>across all edges</strong> to the same target node, not per-edge. This ensures that bindings from different source nodes to the same list port receive unique, sequential indices.</li><li>Non-list bindings are not modified.</li><li>Compaction runs on: <code>onConnect</code>, <code>updateEdge</code>, <code>removeEdgeById</code>, <code>removeNodeById</code>.</li></ul><h3 id="handle-computation-computeinputhandlesbyportkey" tabindex="-1">Handle Computation (<code>computeInputHandlesByPortKey</code>) <a class="header-anchor" href="#handle-computation-computeinputhandlesbyportkey" aria-label="Permalink to &quot;Handle Computation (`computeInputHandlesByPortKey`)&quot;">​</a></h3><ul><li>Counts connected bindings across ALL incoming edges to the target node for each list port.</li><li>Generates <code>connectedCount + 1</code> handle IDs (connected slots + 1 placeholder).</li><li>Result is passed to <code>DagNodeView</code> as <code>inputHandlesByPortKey</code> prop, driving handle rendering.</li></ul><h3 id="disconnection-edge-node-removal" tabindex="-1">Disconnection (Edge/Node Removal) <a class="header-anchor" href="#disconnection-edge-node-removal" aria-label="Permalink to &quot;Disconnection (Edge/Node Removal)&quot;">​</a></h3><ul><li>When an edge is removed (<code>removeEdgeById</code>), <code>compactListBindings()</code> re-indexes remaining list bindings so indices remain sequential with no gaps.</li><li>When a node is removed (<code>removeNodeById</code>), all edges involving that node are removed, then compaction runs on remaining edges.</li><li><strong>Handle shrinkage</strong>: After disconnection and compaction, <code>computeInputHandlesByPortKey</code> recalculates handles. The placeholder count adjusts to <code>remainingConnections + 1</code>, so previously occupied slots disappear. There is no stale handle retention.</li></ul><h3 id="edge-to-reactflow-mapping-toedge" tabindex="-1">Edge-to-ReactFlow Mapping (<code>toEdge</code>) <a class="header-anchor" href="#edge-to-reactflow-mapping-toedge" aria-label="Permalink to &quot;Edge-to-ReactFlow Mapping (`toEdge`)&quot;">​</a></h3><ul><li>Each <code>IDagEdgeDefinition</code> maps to one React Flow <code>Edge</code>.</li><li><code>sourceHandle</code> and <code>targetHandle</code> are set from the <strong>first binding</strong> of the edge.</li><li>An edge with multiple bindings (e.g., same source node sending to <code>images[0]</code> and <code>prompt</code>) is visually rendered as a single edge line; the full binding list is shown in the edge label/tooltip.</li></ul><h3 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h3><ol><li>List binding indices for a given (targetNodeId, listPortKey) are always sequential <code>[0, 1, 2, ...]</code> with no gaps after any mutation.</li><li>Exactly one placeholder handle exists per list port at all times (connected count + 1).</li><li>No two bindings across all edges may share the same (targetNodeId, listInputKey) identity.</li><li><code>dependsOn</code> is recomputed from edges after any edge addition or removal.</li></ol><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Package</th><th>Role</th></tr></thead><tbody><tr><td><code>@robota-sdk/dag-core</code></td><td>Domain types (<code>IDagDefinition</code>, <code>IDagNode</code>, <code>INodeManifest</code>, <code>TRunProgressEvent</code>, etc.)</td></tr><tr><td><code>@robota-sdk/dag-api</code></td><td>Controller contracts (<code>IProblemDetails</code>, <code>IDefinitionListItem</code>)</td></tr><tr><td><code>@xyflow/react</code></td><td>React Flow graph rendering</td></tr><tr><td><code>@robota-sdk/dag-node-*</code></td><td>devDependencies only — used for testing node catalog and port definitions</td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li>Unit tests: <code>port-editor-utils.test.ts</code> (port editing helpers), <code>canvas-utils.test.ts</code> (list binding compaction across multi-edge scenarios, handle computation), <code>comfyui-field-renderers.test.ts</code> (ComfyUI input spec parsing tests).</li><li>Contract tests: <code>designer-api-contract.test.ts</code> (validates <code>hasValidRunResult</code> contract for <code>IRunResult</code> shape — status, dagRunId, traces, nodeErrors, totalCredits).</li><li>API client HTTP request/response shape tests and WebSocket reconnection logic tests are planned.</li><li>The designer also relies on integration testing through app-level UI tests.</li><li>Coverage priorities: API client request/response contract validation, WebSocket reconnection logic, hook state management, component rendering with manifests and definitions.</li><li>Run: <code>pnpm --filter @robota-sdk/dag-designer test</code></li></ul>',52)]))}const h=o(d,[["render",a]]);export{u as __pageData,h as default};
